// src/App.js
import React from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import Employee from './components/Employee'; // Employee Page
import Company from './components/Company'; // Company Page
import WorkEntry from './components/WorkEntry'; // Work Entry Page
import WorkDetails from './components/WorkDetails'; // Work Details Page
import CreateCompany from './components/CreateCompany'; // Create Company Page
import Register from './components/Register';


function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Login />} />
        <Route path="/login" element={<Login />} />
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/employee" element={<Employee />} />
        <Route path="/company" element={<Company />} />
        <Route path="/record" element={<WorkDetails />} />
        <Route path="/work-entry" element={<WorkEntry />} />
        <Route path="/work-details:id" element={<WorkDetails />} />
        <Route path="/create-company" element={<CreateCompany />} />
        <Route path="/register" element={<Register />} />
      </Routes>
    </Router>
  );
}

export default App;
